// Script Continued Below

function onSubmit() {
    var formAction = g_form.getActionName();
    if (formAction == 'Reopen') {
		// 2.7.0 | 2021-11-08 | mmcc | DFCT0010645 - Platform Reopen Task button does not open modal for some Views
        // if (g_form.getValue('active') != 'false') {
            // return false;
        // }
		if (g_scratchpad.active != 'false') {
			return false;
		}

        if (isNotActiveParent()) {
            return false;
        }

        if (isClosedTooLong()) {
            return false;
        }

		// STRY0137377 - always open to get the comment
		confirmReopenTasks();
		return false;
    }
}

// Use this function to show either a widget or UI Page modal
function confirmReopenTasks() {
	var taskNumberShortDescription = g_scratchpad.taskerNumber + ': ' + g_form.getValue('short_description');
    var messageTitle = getMessage('Tasker - Title - Reopen Selection for') + taskNumberShortDescription;

    // Use widget for Portal
    if (typeof spModal != 'undefined') {
        spModal.open({
            title: messageTitle,
            backdrop: 'static',
            widget: 'tasker_modal_reopen_tasks_prompt',
            widgetInput: {
                'taskSysId': g_form.getUniqueValue()
            },
			//2.8.0 | 2022-04-28 | mmcc | DFCT0010879 - Reopen Task button modal should display all options on the same line as the "Radio button"; add size
			size: 'lg',
            buttons: [],
            // Hide the <div> with class modal-footer that gets auto inserted from spModal, adds an element style
            footerStyle: {
                'display': 'none'
            }
        }).then(function() {
            //jslog('numberofsubtasks');
        });
        return false;
    } else if (typeof spModal == 'undefined') {
		// STRY0119137 - STRY0119138 (corrected platform page name while working other story)
        // For Platform use UI Page named: x_153465_discovert_reopen_task_prompt
        var gm = new GlideModal('x_153465_discovert_reopen_task_prompt');
        gm.setTitle(messageTitle);
        gm.setPreference('sysparm_taskSysId', g_form.getUniqueValue());
		// 2.8.0 | 2022-04-28 | mmcc | DFCT0010879 - Reopen Task button modal should display all options on the same line as the "Radio button"; set to 900
        // gm.setWidth(550);
		gm.setWidth(900);
        gm.render();
    }
}

function isClosedTooLong() {
    var result = false;

    // STRY0016025- RAJ 2019-04-20 - Determine if Tasker close date is beyond the allowable reopen days
    if (g_scratchpad.closed_to_long_to_reopen == 'true' || g_scratchpad.closed_to_long_to_reopen == true) {
        g_form.addErrorMessage(g_form.getValue('number') + ' ' + getMessage('Tasker - Closed too long to reopen 1') + ' ' +
            g_scratchpad.ReopenMaxDays + ' ' + getMessage('Tasker - Closed too long to reopen 2') + ' ' + g_scratchpad.closed_at +
            getMessage('Tasker - Closed too long to reopen 3'));

        result = true;
    }

    return result;
}

// Task State 3 = Completed; 4 = Closed Incomplete; 7 = Cancelled should have active = 'false'
function isNotActiveParent() {
    var result = false;

    if (g_scratchpad.parent_sys_id + '' != '' && g_scratchpad.parent_active != 'true') {

		// STRY0113839 
		var ga = new GlideAjax("client_tasker_User_Form_Preferences");
		ga.addParam('sysparm_name', 'get_URL_for_Task_Based_on_Prefrences');
		ga.addParam('sysparam_sys_id', g_scratchpad.parent_sys_id);
		ga.addParam('sysparam_current_view', 'sp');
		ga.getXML(function(response){
			var answer = response.responseXML.documentElement.getAttribute("answer");
			var url = answer + '&state=3&order=1';

			g_form.addErrorMessage(" <b>" + getMessage('Tasker - Reopen Parent is not active - start') + " " + '<a href=' + url + '>' +
									g_scratchpad.parent_number + '</a>' + ' ' + getMessage('Tasker - Reopen Parent is not active - end') + '</b>');
		});

        result = true;
    }

    return result;
}
